import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';

class SettingsBlock extends React.Component {
  render() {
    return (
      <div className="settings-block" onClick={this.props.handleClick}>
        <div id={`${this.props.type}-label`}>{this.props.label}</div>
        <div className="settings-buttons-outer">
          <div
            id={`${this.props.type}-decrement`}
            className="plus-minus button-effect"
          >
            <Minus />
          </div>
          <div id={`${this.props.type}-length`}>{this.props.duration}</div>
          <div
            id={`${this.props.type}-increment`}
            className="plus-minus button-effect"
          >
            <Plus />
          </div>
        </div>
      </div>
    );
  }
}

class Clock extends React.Component {
  render() {
    return (
      <div className="clock-inner">
        <div className="clock-title" id="timer-label">
          {this.props.currentType}
        </div>
        <div
          className="clock-time"
          data-under-one-min={this.props.rawTime < 60}
          id="time-left"
        >
          {this.props.parsedTime}
        </div>
        <div className="clock-icons">
          <div
            className="button-effect clock-icon"
            onClick={this.props.playPauseClick}
            id="start_stop"
          >
            {this.props.isClockRunning ? <Pause /> : <Play />}
          </div>
          <div
            className="button-effect clock-icon"
            onClick={this.props.resetClick}
            id="reset"
          >
            <Refresh />
          </div>
        </div>
      </div>
    );
  }
}

