const accurateInterval = (callback, delay) => {
  const now = new Date();
  const start = now.getMilliseconds();
  let timeout;
  const customSetTimeout = () => {
    const nextSecond = new Date();
    nextSecond.setMilliseconds(start + delay);
    timeout = setTimeout(() => {
      callback();
      customSetTimeout();
    }, nextSecond.getTime() - Date.now());
  };
  customSetTimeout();

  const cancel = () => {
    clearTimeout(timeout);
  };
  return { cancel };
};

class App extends React.Component {
  state = {
    sessDur: 25,
    breakDur: 5,
    isDark: true,
    currentTime: 25 * 60,
    currentType: 'session',
    isClockRunning: false,
  };
  audio = React.createRef();

  toggleTheme = ev => {
    this.setState(state => ({
      isDark: !state.isDark,
    }));
  };
  handlePlusMinusClick = ev => {
    const target = ev.target.closest('.plus-minus');
    if (target !== undefined && target !== null) {
      if (this.state.isClockRunning === false) {
        const id = target.id;
        const [type, action] = id.split('-');
        const key = type === 'session' ? 'sessDur' : 'breakDur';
        this.setState(state => {
          let newDuration = state[key] + (action === 'increment' ? 1 : -1);
          if (newDuration > 60) newDuration = 60;
          else if (newDuration <= 0) newDuration = 1;

          return {
            [key]: newDuration,
            currentType: 'session',
            currentTime: newDuration * 60,
          };
        });
      }
    }
  };

  getParsedTime = () => {
    const seconds = this.state.currentTime % 60;
    const minutes = (this.state.currentTime - seconds) / 60;
    return `${('0' + minutes).slice(-2)}:${('0' + seconds).slice(-2)}`;
  };

  togglePause = () => {
    const shouldClockRun = !this.state.isClockRunning;
    this.setState({
      isClockRunning: shouldClockRun,
    });
    if (this.interval) {
      this.interval.cancel();
      delete this.interval;
    }

    if (shouldClockRun) {
      this.interval = accurateInterval(this.tick, 1000);
    }
  };

  tick = () => {
    const currentTime = this.state.currentTime - 1;
    if (currentTime <= -1) {
      this.setState(state => ({
        currentType: state.currentType === 'session' ? 'break' : 'session',
        currentTime:
          (state.currentType === 'session' ? state.breakDur : state.sessDur) *
          60,
      }));

      const audio = this.audio.current;
      audio.currentTime = 0;
      audio.play();
    } else {
      this.setState(state => ({
        currentTime,
      }));
    }
  };

  reset = () => {
    if (this.interval) {
      this.interval.cancel();
      delete this.interval;
    }

    this.setState(state => ({
      sessDur: 25,
      breakDur: 5,
      currentType: 'session',
      currentTime: state.sessDur * 60,
      isClockRunning: false,
    }));

    const audio = this.audio.current;
    audio.pause();
    audio.currentTime = 0;
  };

  render() {
    return (
      <React.StrictMode>
        <div data-theme={this.state.isDark ? 'dark' : 'light'}>
          <header className="App-header">
            <div className="header-title">25 + 5 Clock</div>
            <div
              className="theme-toggle button-effect"
              onClick={this.toggleTheme}
            >
              {this.state.isDark ? <Moon /> : <Sun />}
            </div>
          </header>
          <main className="App-main">
            <div className="settings">
              <SettingsBlock
                handleClick={this.handlePlusMinusClick}
                duration={this.state.breakDur}
                label="Break duration"
                type="break"
              />
              <SettingsBlock
                handleClick={this.handlePlusMinusClick}
                duration={this.state.sessDur}
                label="Session duration"
                type="session"
              />
            </div>
            <div className="clock">
              <Clock
                currentType={
                  this.state.currentType === 'session' ? 'Session' : 'Break'
                }
                parsedTime={this.getParsedTime()}
                rawTime={this.state.currentTime}
                playPauseClick={this.togglePause}
                resetClick={this.reset}
                isClockRunning={this.state.isClockRunning}
              />
            </div>
          </main>
          <audio
            src="https://raw.githubusercontent.com/freeCodeCamp/cdn/master/build/testable-projects-fcc/audio/BeepSound.wav"
            preload="auto"
            ref={this.audio}
            id="beep"
          />
        </div>
      </React.StrictMode>
    );
  }
}
ReactDOM.render(<App />, document.getElementById('root'));
